    77→  const normalized = normalizeText(messageText);
    78→  const words = normalized.split(/\s+/);
    79→
    80→  for (const word of ABUSE_WORDS_EN) {
    81→    const wordNorm = normalizeText(word);
    82→    if (normalized.includes(wordNorm)) {
    83→      return {
    84→        isAbusive: true,
    85→        severity: word.length <= 4 ? 'low' : 'high',
    86→        type: 'abusive_language',
    87→        language: 'en',
    88→        matched: word
    89→      };
    90→    }
    91→  }
    92→
    93→  for (const word of ABUSE_WORDS_HI) {
    94→    const wordNorm = word.toLowerCase().replace(/\s+/g, '');
    95→    const cleanNorm = normalized.replace(/\s+/g, '');
    96→    if (cleanNorm.includes(wordNorm) || normalized.includes(word.toLowerCase())) {
    97→      return {
    98→        isAbusive: true,
    99→        severity: 'high',
   100→        type: 'abusive_language',
   101→        language: 'hi',
   102→        matched: word
   103→      };
   104→    }
   105→  }
   106→
   107→  for (const pattern of HARASSMENT_PATTERNS) {
   108→    if (pattern.test(messageText)) {
   109→      return {
   110→        isAbusive: true,
   111→        severity: 'severe',
   112→        type: 'harassment_threat',
   113→        language: 'en',
   114→        matched: pattern.toString()
   115→      };
   116→    }
   117→  }
   118→
   119→  const capsOnlyWords = words.filter(w => w.length >= 3 && /^[A-Z]+$/.test(messageText.split(/\s+/).find(orig => orig.toLowerCase() === w) || ''));
   120→
   121→  return { isAbusive: false };
