   191→export const handleAbuseViolation = async (uid, messageText, messageDocRef, detection) => {
   192→  if (!uid) return { action: 'none' };
   193→
   194→  const offenseCount = getUserOffenseCount(uid);
   195→  addUserOffense(uid, { type: detection.type, severity: detection.severity });
   196→
   197→  let action = 'none';
   198→  let userMessage = '';
   199→  let muteUntil = null;
   200→
   201→  if (messageDocRef) {
   202→    try {
   203→      await deleteDoc(messageDocRef);
   204→    } catch (err) {
   205→      console.error('[AbuseDetection] Error deleting message:', err);
   206→    }
   207→  }
   208→
   209→  if (detection.severity === 'severe' || offenseCount >= OFFENSE_CONFIG.SEVERE_BAN_THRESHOLD) {
   210→    await applyBan(uid, `Automatic ban: severe abuse/threats (${offenseCount + 1} offenses)`);
   211→    await logAbuseViolation(uid, messageText, detection, 'auto_ban');
   212→    action = 'auto_ban';
   213→    userMessage = '🚫 You have been automatically banned for severe abuse or repeated violations.';
   214→  } else if (offenseCount >= OFFENSE_CONFIG.MUTE_THRESHOLD) {
   215→    const muteIndex = Math.min(
   216→      offenseCount - OFFENSE_CONFIG.MUTE_THRESHOLD,
   217→      OFFENSE_CONFIG.MUTE_DURATIONS.length - 1
   218→    );
   219→    const muteDuration = OFFENSE_CONFIG.MUTE_DURATIONS[muteIndex];
   220→    muteUntil = await applyMute(uid, muteDuration, `AutoMod: abusive language (offense #${offenseCount + 1})`);
   221→    await logAbuseViolation(uid, messageText, detection, 'auto_mute');
   222→    action = 'auto_mute';
   223→    const mins = Math.ceil(muteDuration / 60000);
   224→    userMessage = `⚠️ Your message was removed and you have been muted for ${mins >= 60 ? Math.ceil(mins / 60) + ' hour(s)' : mins + ' minute(s)'} for abusive language.`;
   225→  } else {
   226→    await logAbuseViolation(uid, messageText, detection, 'warning');
   227→    action = 'warning';
   228→    userMessage = '⚠️ Warning: Your message was removed for violating community guidelines. Further violations will result in a mute.';
   229→  }
   230→
   231→  return { action, userMessage, muteUntil };
   232→};
