    25→const stringSimilarity = (a, b) => {
    26→  if (!a || !b) return 0;
    27→  if (a === b) return 1;
    28→  const la = a.toLowerCase().trim();
    29→  const lb = b.toLowerCase().trim();
    30→  if (la === lb) return 1;
    31→  const longer = la.length > lb.length ? la : lb;
    32→  const shorter = la.length > lb.length ? lb : la;
    33→  if (longer.length === 0) return 1;
    34→  const editDistance = (s1, s2) => {
    35→    const dp = Array.from({ length: s1.length + 1 }, (_, i) =>
    36→      Array.from({ length: s2.length + 1 }, (_, j) => (i === 0 ? j : j === 0 ? i : 0))
    37→    );
    38→    for (let i = 1; i <= s1.length; i++) {
    39→      for (let j = 1; j <= s2.length; j++) {
    40→        dp[i][j] = s1[i - 1] === s2[j - 1]
    41→          ? dp[i - 1][j - 1]
    42→          : 1 + Math.min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
    43→      }
    44→    }
    45→    return dp[s1.length][s2.length];
    46→  };
    47→  return (longer.length - editDistance(longer, shorter)) / longer.length;
    48→};
