  1324→
  1325→const strSimilarity = (a, b) => {
  1326→    if (!a || !b) return 0;
  1327→    const la = a.toLowerCase().trim(), lb = b.toLowerCase().trim();
  1328→    if (la === lb) return 1;
  1329→    const longer = la.length > lb.length ? la : lb;
  1330→    const shorter = la.length > lb.length ? lb : la;
  1331→    if (!longer.length) return 1;
  1332→    const dp = Array.from({ length: shorter.length + 1 }, (_, i) => i);
  1333→    for (let i = 1; i <= longer.length; i++) {
  1334→        let prev = i;
  1335→        for (let j = 1; j <= shorter.length; j++) {
  1336→            const tmp = dp[j];
  1337→            dp[j] = longer[i-1] === shorter[j-1] ? dp[j-1] : 1 + Math.min(dp[j], prev, dp[j-1]);
  1338→            prev = tmp;
  1339→        }
  1340→    }
  1341→    return (longer.length - dp[shorter.length]) / longer.length;
  1342→};
